    /// <summary>Fills in missing catalog rows so every job-search category has listings (fixes older DBs seeded before the full set existed).</summary>
    private static async Task SeedCanonicalJobListingsAsync(ApplicationDbContext db, CancellationToken ct)
    {
        var canonical = GetCanonicalJobListings();
        var existingTitles = await db.JobListings.AsNoTracking()
            .Select(j => j.Title)
            .ToListAsync(ct);
        var existingSet = existingTitles
            .Where(t => !string.IsNullOrWhiteSpace(t))
            .ToHashSet(StringComparer.OrdinalIgnoreCase);
        var missing = canonical.Where(j => j.Title != null && !existingSet.Contains(j.Title)).ToList();
        if (missing.Count == 0) return;
        await db.JobListings.AddRangeAsync(missing, ct);
    }

    public static async Task SeedAsync(ApplicationDbContext db, IHostEnvironment? env = null, CancellationToken ct = default)
    {
        var existingIds = await db.IndustrySkillGaps.Select(x => x.IndustryId).ToListAsync(ct);
        var toAdd = GetAllIndustries().Where(g => !existingIds.Contains(g.IndustryId)).ToArray();
        if (toAdd.Length > 0)
            await db.IndustrySkillGaps.AddRangeAsync(toAdd, ct);

        await SeedCanonicalJobListingsAsync(db, ct);

        // Align legacy demo rows with the expanded global category list (Job Search / Top 10 filters).
        await db.JobListings
            .Where(j => j.Category == "Creative" && j.Sector == "Creative")
            .ExecuteUpdateAsync(s => s
                .SetProperty(j => j.Category, "Creative & Design")
                .SetProperty(j => j.Sector, "Creative & Design"), ct);

        if (!await db.MarketTrends.AnyAsync(ct))
        {
            var trends = new[]
            {
                new MarketTrend { Category = "Technology", Title = "Job Demand Growth", Description = "Data Science and Software Engineering demand", TrendDataJson = "{\"labels\":[\"2020\",\"2021\",\"2022\",\"2023\",\"2024\"],\"data\":[100,115,130,145,165]}", UpdatedAt = DateTime.UtcNow },
                new MarketTrend { Category = "Healthcare", Title = "Healthcare Hiring", Description = "Nursing and health tech growth", TrendDataJson = "{\"labels\":[\"2020\",\"2021\",\"2022\",\"2023\",\"2024\"],\"data\":[100,108,118,128,140]}", UpdatedAt = DateTime.UtcNow },
                new MarketTrend { Category = "Finance", Title = "Finance Sector", Description = "FinTech and analytics demand", TrendDataJson = "{\"labels\":[\"2020\",\"2021\",\"2022\",\"2023\",\"2024\"],\"data\":[100,105,112,120,130]}", UpdatedAt = DateTime.UtcNow },
            };
            await db.MarketTrends.AddRangeAsync(trends, ct);
        }

        await db.SaveChangesAsync(ct);

        // Development-only demo account so login can be verified on a fresh database
        if (env?.IsDevelopment() == true)
        {
            const string demoEmail = "demo@careerpath.local";
            if (!await db.Users.AnyAsync(u => u.Email == demoEmail, ct))
            {
                db.Users.Add(new User
                {
                    Name = "Demo User",
                    Email = demoEmail,
                    PasswordHash = BCrypt.Net.BCrypt.HashPassword("Demo123!"),
                    CreatedAt = DateTime.UtcNow,
                });
                await db.SaveChangesAsync(ct);
            }
        }
    }
